import type { TextareaHTMLAttributes } from 'react';
import type { TestComponentProps } from '../../types/test-component';
export type TextAreaSize = 'small' | 'medium';
export type HelperPositionType = 'absolute' | 'block';
export interface TextAreaProps extends TextareaHTMLAttributes<HTMLTextAreaElement>, TestComponentProps {
    /**
     * Заголовок поля.
     */
    label?: string;
    /**
     * Идентификатор для текстового поля. Подставляется и в label.
     */
    textareaId?: string;
    /**
     * Название класса для текстового поля.
     */
    textareaClassName?: string;
    /**
     * Размеры.
     */
    size?: TextAreaSize;
    /**
     * Признак, ошибка / нет ошибки.
     */
    error?: boolean;
    /**
     * Признак, блокирован / разблокирован.
     */
    disabled?: boolean;
    /**
     * Вспомогательный текст
     */
    helperText?: string;
    /**
     * Растягивает поле на всю ширину родителя.
     */
    fullWidth?: boolean;
    /**
     * Автоматическое увеличение под вводимый текст.
     */
    autoHeight?: boolean;
    /**
     * Максимальная высота в пикселях,раьотает только с autoHeight.
     */
    maxHeight?: number;
    /**
     * Позиционирование helper text.
     */
    helperPosition?: HelperPositionType;
}
export interface StyledTextarea extends TextAreaProps {
    size: TextAreaSize;
}
export interface MarginTextarea {
    medium: number;
    mediumLabel: number;
    small: number;
    smallLabel: number;
}
